class AutocompleteCombobox(ttk.Combobox):
    def set_completion_list(self, completion_list):
        self._completion_list = sorted(completion_list, key=str.lower)
        self.configure(values=self._completion_list)
        self.bind('<KeyRelease>', self.handle_keyrelease)

    def handle_keyrelease(self, event):
        # Ignore navigation and control keys
        if event.keysym in ("BackSpace", "Left", "Right", "Up", "Down", "Home", "End", "Return", "Tab"):
            return

        typed = self.get().lower()
        if typed == '':
            filtered = self._completion_list
        else:
            filtered = [item for item in self._completion_list if typed in item.lower()]

        self.configure(values=filtered if filtered else ["<No matches>"])
        
        # Open the dropdown list to show filtered results if there are matches and it's not already open
        if filtered:
            self.event_generate('<Down>')

