MASTER_SHEET_NAME = "Data"
EMAIL_REGEX = r"^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$"
PHONE_REGEX = r"^\d{10}$"

def encrypt_excel_with_password(file_path: str, password: str):
    try:
        excel = win32.gencache.EnsureDispatch('Excel.Application')
        excel.Visible = False
        workbook = excel.Workbooks.Open(file_path)
        workbook.Password = password
        workbook.Save()
        workbook.Close(SaveChanges=1)
        excel.Quit()
        del workbook
        del excel
        time.sleep(0.7)
    except Exception as e:
        raise RuntimeError(f"Encryption failed: {e}")

def sanitize_filename(filename: str) -> str:
    return re.sub(r'[\\/*?:"<>|]', '', filename)

def create_user_excel_file(filepath, headers, data_rows):
    try:
        workbook = xlsxwriter.Workbook(filepath)
        worksheet = workbook.add_worksheet(MASTER_SHEET_NAME)
        worksheet.protect(PASSWORD)
        for col, head in enumerate(headers):
            worksheet.write(0, col, head)
        for row_num, row_data in enumerate(data_rows, start=1):
            for col_num, val in enumerate(row_data):
                worksheet.write(row_num, col_num, val)
        workbook.close()
        encrypt_excel_with_password(filepath, PASSWORD)
    except Exception as e:
        raise RuntimeError(f"Failed creating/encrypting user file: {e}")

def get_headers(fields):
    return ["S. No"] + fields + ["Duplicate", "Date", "Time Zone"]

def check_email(email):
    return re.match(EMAIL_REGEX, email) is not None

def check_phone(phone):
    return re.match(PHONE_REGEX, phone) is not None

